  libdata[libdataItem++] = new Array("./spdffiledescription__define.html#SpdfFileDescription::init", "SpdfFileDescription::init", 'routine in <a href="./spdffiledescription__define.html">spdffiledescription__define.pro</a>', "spdffiledescription__define.pro", "", "SpdfFileDescription::init", " Creates an SpdfFileDescription object.   If access to the Internet is through an HTTP proxy, the caller  should ensure that the HTTP_PROXY environment is correctly set  before this method is called.  The HTTP_PROXY value should be of  the form  http://username:password@hostname:port/.   ", "thumbnailDescription            if file contains thumbnail images, then this describes             them.  thumbnailId            if file contains thumbnail images, then this contains             an opaque value that the server needs to provide             full-sized versions of the images.  name            name of file.  mimeType            (Multipurpose Internet Mail Extensions) MIME-type of file.  timeInterval            time interval of the data in this file.  length            length (in bytes) of file.  lastModified            date file was last modified (julday value).  ", "          -1", " reference to an SpdfFileDescription object.  ");
  
