libdata[libdataItem++] = new Array("./spdfgetdata.html", "spdfgetdata.pro", '.pro file in <a href="./dir-overview.html">./ directory</a>', "spdfgetdata.pro", " B. Harris  ", "", " This file contains a procedure-oriented wrapper that integrates  functionality from the SpdfCdas class (IDL client interface to  <a href= https://cdaweb.gsfc.nasa.gov/WebServices >  Coordinated Data Analysis System Web Services</a> (CDAS WSs))  and the  <a href= https://spdf.gsfc.nasa.gov/CDAWlib.html >CDAWlib</a>  library.   ", "", "          -1", " Copyright (c) 2010-2023 United States Government as      represented by the National Aeronautics and Space      Administration. No copyright is claimed in the United States      under Title 17, U.S.Code. All Other Rights Reserved.   ");
  
  
